console.log(`Destination : ${previewData.destination}`);
console.log(`Preview URL : ${previewUrl}`);
console.log(`Video URL   : http://localhost:8000${previewData.video_url}`);
console.log(`Chars       : ${previewData.char_count} / 2200`);
console.log(`Within limit: ${previewData.within_limit}`);
console.log('----------------------------------------');
console.log('Caption preview:');
console.log(previewData.caption.substring(0, 200) + '...');
console.log('Hashtags:', previewData.hashtag_block.substring(0, 120) + '...');
console.log('========================================\n');

return [{
  json: {
    status: 'preview_ready',
    preview_id: saveResult.preview_id,
    preview_url: previewUrl,
    destination: previewData.destination,
    video_url: `http://localhost:8000${previewData.video_url}`,
    caption_preview: previewData.caption.substring(0, 200) + '...',
    hashtag_count: previewData.hashtags.length,
    char_count: previewData.char_count,
    within_limit: previewData.within_limit,
    next_step: 'Open the preview URL, review caption and hashtags, then approve to publish.',
  }
}];
